// src/App.jsx
import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Polyline, Marker } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import gpsData from './frontend_data_gps.json'; // Importa o JSON (já corrigido)
import CarSprite from './components/CarSprite/CarSprite';

// Fix para ícone do Leaflet (remover se já tiver no seu código)
import L from 'leaflet';
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: require('leaflet/dist/images/marker-icon-2x.png'),
  iconUrl: require('leaflet/dist/images/marker-icon.png'),
  shadowUrl: require('leaflet/dist/images/marker-shadow.png'),
});

const App = () => {
  const [selectedCourseIndex, setSelectedCourseIndex] = useState(0);
  const [currentPointIndex, setCurrentPointIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  
  const vehicle = gpsData.vehicle;
  const courses = gpsData.courses || [];
  const currentCourse = courses[selectedCourseIndex];
  const points = currentCourse?.gps || [];
  
  // Ponto atual para o marcador
  const currentPoint = points[currentPointIndex] || null;

  // Animação: Avança ponto a ponto
  useEffect(() => {
    let interval = null;

    if (isPlaying && currentPointIndex < points.length) {
      interval = setInterval(() => {
        setCurrentPointIndex(prev => {
          if (prev >= points.length - 1) {
            setIsPlaying(false); // Para ao chegar no fim
            return prev;
          }
          return prev + 1;
        });
      }, 500); // Velocidade da animação (ms)
    }

    return () => clearInterval(interval);
  }, [isPlaying, currentPointIndex, points.length]);

  // Handler para trocar de rota
  const handleRouteChange = (e) => {
    setSelectedCourseIndex(Number(e.target.value));
    setCurrentPointIndex(0);
    setIsPlaying(false);
  };

  return (
    <div className="app-container">
      <header>
        <h1>🚗 Rastreamento 3D</h1>
        <div className="controls">
          <select value={selectedCourseIndex} onChange={handleRouteChange}>
            {courses.map((c, i) => (
              <option key={i} value={i}>Rota {i + 1}</option>
            ))}
          </select>
          <button onClick={() => setIsPlaying(!isPlaying)}>
            {isPlaying ? ' Pausar' : '▶ Play'}
          </button>
          <button onClick={() => { setCurrentPointIndex(0); setIsPlaying(false); }}>
            🔄 Reiniciar
          </button>
        </div>
      </header>

      <div className="map-wrapper">
        <MapContainer 
          center={[-23.963214, -46.28054]} // Centro inicial (Guarujá)
          zoom={14} 
          style={{ height: '100%', width: '100%' }}
        >
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; OpenStreetMap contributors'
          />

          {/* Desenha a linha da rota */}
          {points.length > 0 && (
            <Polyline 
              positions={points.map(p => [p.latitude, p.longitude])} 
              color="#007bff" 
              weight={4} 
            />
          )}

          {/* Marker do carro com o Sprite Animado */}
          {currentPoint && (
            <Marker position={[currentPoint.latitude, currentPoint.longitude]}>
              <CarSprite 
                direction={currentPoint.direction || 0} 
                color={vehicle.color?.replace(/\s/g, '') || '#FFEB3B'} 
              />
            </Marker>
          )}
        </MapContainer>
      </div>

      {/* Info do veículo */}
      <div className="info-panel">
        <p><strong>Placa:</strong> {vehicle.plate?.trim()}</p>
        <p><strong>Velocidade:</strong> {currentPoint?.speed || 0} km/h</p>
        <p><strong>Direção:</strong> {currentPoint?.direction || 0}°</p>
        <p><strong>Ponto:</strong> {currentPointIndex} / {points.length}</p>
      </div>
    </div>
  );
};

export default App;
